import type {
  AuthPluginComponents,
  AuthPlugin as AuthPluginPrimitive
} from "@better-auth-ui/react"

declare module "@better-auth-ui/core" {
  /** Widens `useAuth().plugins` to the shadcn-typed `AuthPlugin`. */
  interface AuthPluginRegister {
    shadcn: AuthPlugin
  }
}

/** Props the shadcn `<Auth>` router spreads onto plugin-contributed auth views. */
export type AuthViewProps = {
  className?: string
  socialLayout?: "auto" | "horizontal" | "vertical" | "grid"
  socialPosition?: "top" | "bottom"
}

/** Props the shadcn `<Settings>` router spreads onto plugin-contributed settings views. */
export type SettingsViewProps = {
  className?: string
}

/** Shadcn plugin type. Plugin authors import this from `@/lib/auth-plugin`. */
export type AuthPlugin = AuthPluginPrimitive<
  AuthPluginComponents,
  AuthViewProps,
  SettingsViewProps
>

import {
  passkeyPlugin as corePasskeyPlugin,
  type PasskeyPluginOptions
} from "@better-auth-ui/core/plugins"

import { PasskeyButton } from "@/components/auth/passkey-button"
import { Passkeys } from "@/components/settings/security/passkeys"
import type { AuthPlugin } from "../auth-plugin"

export function passkeyPlugin(options: PasskeyPluginOptions = {}) {
  return {
    ...corePasskeyPlugin(options),
    authButtons: [PasskeyButton],
    securityCards: [Passkeys]
  } satisfies AuthPlugin
}

"use client"

import { type AuthView, authMutationKeys } from "@better-auth-ui/core"
import {
  type PasskeyAuthClient,
  useAuth,
  useAuthPlugin,
  useSignInPasskey
} from "@better-auth-ui/react"
import { useIsMutating } from "@tanstack/react-query"
import { Fingerprint } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Spinner } from "@/components/ui/spinner"
import { passkeyPlugin } from "@/lib/passkey/passkey-plugin"
import { cn } from "@/lib/utils"

export type PasskeyButtonProps = {
  /** @remarks `AuthView` */
  view?: AuthView
}

/**
 * "Continue with Passkey" button rendered alongside the password sign-in form.
 *
 * Hidden on the sign-up view where passkey sign-in isn't applicable.
 *
 * @param view - Current auth view. Hides the button on `"signUp"`.
 */
export function PasskeyButton({ view }: PasskeyButtonProps) {
  const { authClient, localization, redirectTo, navigate } = useAuth()
  const { localization: passkeyLocalization } = useAuthPlugin(passkeyPlugin)

  const { mutate: signInPasskey, isPending: passkeyPending } = useSignInPasskey(
    authClient as PasskeyAuthClient,
    {
      onSuccess: () => navigate({ to: redirectTo })
    }
  )

  const signInMutating = useIsMutating({
    mutationKey: authMutationKeys.signIn.all
  })
  const signUpMutating = useIsMutating({
    mutationKey: authMutationKeys.signUp.all
  })
  const isPending = signInMutating + signUpMutating > 0

  // Passkey sign-in isn't relevant on the sign-up flow.
  if (view === "signUp") return null

  return (
    <Button
      type="button"
      variant="outline"
      disabled={isPending}
      className={cn("w-full", isPending && "opacity-50 pointer-events-none")}
      onClick={() => signInPasskey()}
    >
      {passkeyPending ? <Spinner /> : <Fingerprint />}
      {localization.auth.continueWith.replace(
        "{{provider}}",
        passkeyLocalization.passkey
      )}
    </Button>
  )
}

"use client"

import {
  type PasskeyAuthClient,
  useAddPasskey,
  useAuth,
  useAuthPlugin,
  useListPasskeys
} from "@better-auth-ui/react"
import { Fingerprint } from "lucide-react"
import { type SyntheticEvent, useState } from "react"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogMedia,
  AlertDialogTitle,
  AlertDialogTrigger
} from "@/components/ui/alert-dialog"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Field, FieldError } from "@/components/ui/field"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Separator } from "@/components/ui/separator"
import { Skeleton } from "@/components/ui/skeleton"
import { Spinner } from "@/components/ui/spinner"
import { passkeyPlugin } from "@/lib/passkey/passkey-plugin"
import { cn } from "@/lib/utils"
import { Passkey } from "./passkey"

export type PasskeysProps = {
  className?: string
}

export function Passkeys({ className }: PasskeysProps) {
  const { authClient, localization } = useAuth()
  const { localization: passkeyLocalization } = useAuthPlugin(passkeyPlugin)

  const { data: passkeys, isPending } = useListPasskeys(
    authClient as PasskeyAuthClient
  )

  const { mutate: addPasskey, isPending: isAdding } = useAddPasskey(
    authClient as PasskeyAuthClient
  )

  const [nameOpen, setNameOpen] = useState(false)
  const [name, setName] = useState("")

  const handleDialogOpenChange = (open: boolean) => {
    setNameOpen(open)
  }

  const handleSubmit = (e: SyntheticEvent<HTMLFormElement>) => {
    e.preventDefault()
    addPasskey(
      { name: name.trim() || undefined },
      {
        onSuccess: () => {
          setNameOpen(false)
          setName("")
        }
      }
    )
  }

  return (
    <div>
      <h2 className="text-sm font-semibold mb-3">
        {passkeyLocalization.passkeys}
      </h2>

      <Card className={cn("p-0", className)}>
        <CardContent className="p-0">
          <Card className="bg-transparent border-0 ring-0 shadow-none">
            <CardContent className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-sm font-medium leading-tight">
                  {passkeyLocalization.passkeysDescription}
                </p>

                <p className="text-muted-foreground text-xs mt-0.5">
                  {passkeyLocalization.passkeysInstructions}
                </p>
              </div>

              <AlertDialog
                open={nameOpen}
                onOpenChange={handleDialogOpenChange}
              >
                <AlertDialogTrigger asChild>
                  <Button className="shrink-0" size="sm" disabled={isPending}>
                    {passkeyLocalization.addPasskey}
                  </Button>
                </AlertDialogTrigger>

                <AlertDialogContent>
                  <form onSubmit={handleSubmit} className="flex flex-col gap-6">
                    <AlertDialogHeader>
                      <AlertDialogMedia>
                        <Fingerprint />
                      </AlertDialogMedia>

                      <AlertDialogTitle>
                        {passkeyLocalization.addPasskey}
                      </AlertDialogTitle>

                      <AlertDialogDescription>
                        {passkeyLocalization.passkeysInstructions}
                      </AlertDialogDescription>
                    </AlertDialogHeader>

                    <Field>
                      <Label htmlFor="passkey-name">
                        {passkeyLocalization.passkey}
                      </Label>

                      <Input
                        id="passkey-name"
                        name="passkey-name"
                        autoFocus
                        placeholder={localization.settings.optional}
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        disabled={isAdding}
                      />

                      <FieldError />
                    </Field>

                    <AlertDialogFooter>
                      <AlertDialogCancel onClick={() => setName("")}>
                        {localization.settings.cancel}
                      </AlertDialogCancel>

                      <AlertDialogAction type="submit">
                        {isAdding && <Spinner />}

                        {passkeyLocalization.addPasskey}
                      </AlertDialogAction>
                    </AlertDialogFooter>
                  </form>
                </AlertDialogContent>
              </AlertDialog>
            </CardContent>
          </Card>

          {isPending ? (
            <>
              <Separator />
              <PasskeySkeleton />
            </>
          ) : (
            passkeys?.map((passkey) => (
              <div key={passkey.id}>
                <Separator />
                <Passkey passkey={passkey} />
              </div>
            ))
          )}
        </CardContent>
      </Card>
    </div>
  )
}

function PasskeySkeleton() {
  return (
    <Card className="bg-transparent border-0 ring-0 shadow-none">
      <CardContent className="flex items-center gap-3">
        <Skeleton className="size-10 rounded-md" />

        <div className="flex flex-col gap-1">
          <Skeleton className="h-4 w-24" />
          <Skeleton className="h-3 w-20" />
        </div>
      </CardContent>
    </Card>
  )
}

"use client"

import {
  type PasskeyAuthClient,
  useAuth,
  useAuthPlugin,
  useDeletePasskey
} from "@better-auth-ui/react"
import { Fingerprint, X } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Spinner } from "@/components/ui/spinner"
import { passkeyPlugin } from "@/lib/passkey/passkey-plugin"

export type PasskeyProps = {
  passkey: {
    id: string
    name?: string | null
    createdAt: Date
  }
}

export function Passkey({ passkey }: PasskeyProps) {
  const { authClient, localization } = useAuth()
  const { localization: passkeyLocalization } = useAuthPlugin(passkeyPlugin)

  const { mutate: deletePasskey, isPending } = useDeletePasskey(
    authClient as PasskeyAuthClient
  )

  const passkeyName = passkey.name || passkeyLocalization.passkey

  return (
    <Card className="bg-transparent border-0 ring-0 shadow-none">
      <CardContent className="flex items-center justify-between gap-3">
        <div className="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
          <Fingerprint className="size-4.5" />
        </div>

        <div className="flex flex-col min-w-0">
          <span className="text-sm font-medium leading-tight">
            {passkeyName}
          </span>

          <span className="text-xs text-muted-foreground">
            {new Date(passkey.createdAt).toLocaleString(undefined, {
              dateStyle: "medium",
              timeStyle: "short"
            })}
          </span>
        </div>

        <Button
          className="ml-auto shrink-0"
          variant="outline"
          size="sm"
          disabled={isPending}
          onClick={() => deletePasskey({ id: passkey.id })}
          aria-label={passkeyLocalization.deletePasskey.replace(
            "{{name}}",
            passkeyName
          )}
        >
          {isPending ? <Spinner /> : <X />}
          {localization.settings.delete}
        </Button>
      </CardContent>
    </Card>
  )
}
